import { configureStore } from "@reduxjs/toolkit";
import userReducer from "..TaskSlice/Features/UserSlice";
import taskReducer from "./Features/TaskSlice"; // استيراد سلايس المهام

export const store = configureStore({
  reducer: {
    users: userReducer,
    tasks: taskReducer, // إضافة المهام هنا
  },
});
